static void
uart_putc(char c)
{
  while ((UART0[UART_LSR] & UART_LSR_THRE) == 0)
    ;
  UART0[0] = (u8)c;
}

static void
uart_puts(const char *s)
{
  while (*s) {
    if (*s == '\n')
      uart_putc('\r');
    uart_putc(*s++);
  }
}

